mapper.select:
select policy_id, policy_name, version, phase, status, del_deadline, del_deadline_unit, archive_flag, arc_del_deadline, arc_del_deadline_unit, related_law, comments,  DATE_FORMAT(regdate,'%Y/%m/%d') as regdate,  DATE_FORMAT(upddate,'%Y/%m/%d') as upddate, reguserid, upduserid
  from cotdl.tbl_piipolicy a 
 where policy_id = #{policy_id, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR}
